import { useState, useEffect } from 'react';
import { ResumeContextProvider, useResume } from './context/ResumeContext';
import LandingPage from './pages/LandingPage';
import BuilderPage from './pages/BuilderPage';

function AppRouter() {
  const [page, setPage] = useState('landing');
  const { state } = useResume();

  useEffect(() => {
    if (window.location.hash) {
      setPage('builder');
    } else if (localStorage.getItem('resumeState')) {
      setPage('builder');
    }
  }, []);

  return page === 'landing' ? (
    <LandingPage onNavigate={() => setPage('builder')} />
  ) : (
    <BuilderPage onStartOver={() => setPage('landing')} />
  );
}

export default function App() {
  return (
    <ResumeContextProvider>
      <AppRouter />
    </ResumeContextProvider>
  );
}

import React, { useState } from 'react';
import { useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { GripVertical, ChevronDown, ChevronUp, Eye, EyeOff, Trash2 } from 'lucide-react';
import { useResume } from '../../context/ResumeContext';
import { motion, AnimatePresence } from 'framer-motion';

// Imports for section editors (to be created)
import HeaderSection from '../sections/HeaderSection';
import SummarySection from '../sections/SummarySection';
import ExperienceSection from '../sections/ExperienceSection';
import EducationSection from '../sections/EducationSection';
import SkillsSection from '../sections/SkillsSection';
import ProjectsSection from '../sections/ProjectsSection';
import CertificationsSection from '../sections/CertificationsSection';
import LanguagesSection from '../sections/LanguagesSection';
import CustomSection from '../sections/CustomSection';

const SectionEditorMap = {
  header: HeaderSection,
  summary: SummarySection,
  experience: ExperienceSection,
  education: EducationSection,
  skills: SkillsSection,
  projects: ProjectsSection,
  certifications: CertificationsSection,
  languages: LanguagesSection,
  custom: CustomSection
};

export default function SectionCard({ section }) {
  const { dispatch } = useResume();
  const [expanded, setExpanded] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState(false);

  // Drag listeners specifically for the handle
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({ id: section.id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    zIndex: isDragging ? 50 : 'auto',
  };

  const handleToggleVis = () => dispatch({ type: 'TOGGLE_SECTION_VISIBILITY', payload: section.id });
  const handleDelete = () => dispatch({ type: 'REMOVE_SECTION', payload: section.id });

  const Editor = SectionEditorMap[section.type];

  return (
    <div
      ref={setNodeRef}
      style={style}
      className={`relative bg-[#1A1A24] rounded-xl shadow-lg border border-[#2E2E3D] transition-all duration-200 ${isDragging ? 'shadow-2xl scale-[1.02]' : ''} ${!section.visible ? 'opacity-40' : ''} ${expanded ? 'border-l-[3px] border-l-[#6C63FF]' : ''}`}
    >
      <div className="flex items-center justify-between p-4 bg-[#1A1A24] rounded-xl">
        <div className="flex items-center space-x-3">
          {/* Drag Handle */}
          <div {...attributes} {...listeners} className="cursor-grab hover:text-[#6C63FF] text-[#8B8A9F] px-1 py-2 rounded focus:outline-none">
            <GripVertical size={20} />
          </div>
          <h3 className={`font-semibold text-[#F1F0FF] capitalize ${!section.visible ? 'line-through text-[#8B8A9F]' : ''}`}>
            {section.type}
          </h3>
        </div>

        <div className="flex items-center space-x-2 text-[#8B8A9F]">
          <button onClick={handleToggleVis} className="hover:text-[#F1F0FF] transition-colors p-1" title="Toggle Visibility">
            {section.visible ? <Eye size={18} /> : <EyeOff size={18} />}
          </button>

          {confirmDelete ? (
            <div className="flex items-center space-x-2 text-sm ml-2 font-medium">
              <span className="text-red-400">Sure?</span>
              <button onClick={handleDelete} className="hover:text-white">Yes</button>
              <button onClick={() => setConfirmDelete(false)} className="hover:text-white">No</button>
            </div>
          ) : (
            <button onClick={() => setConfirmDelete(true)} className="hover:text-red-400 transition-colors p-1" title="Delete">
              <Trash2 size={18} />
            </button>
          )}

          <div className="w-px h-4 bg-[#2E2E3D] mx-2" />

          <button onClick={() => setExpanded(!expanded)} className="hover:text-[#F1F0FF] transition-colors p-1" title="Edit">
            {expanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
          </button>
        </div>
      </div>

      <AnimatePresence>
        {expanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            className="overflow-hidden"
          >
            <div className="p-4 border-t border-[#2E2E3D]">
              {Editor ? <Editor section={section} /> : <p className="text-[#8B8A9F] italic">Editor pending implementation...</p>}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

import React, { useRef } from 'react';
import { useResume } from '../../context/ResumeContext';
import ClassicTemplate from './templates/ClassicTemplate';
import ModernTemplate from './templates/ModernTemplate';
import MinimalTemplate from './templates/MinimalTemplate';
import { Download, Share2 } from 'lucide-react';
import { exportResumePDF } from '../../utils/exportPDF';

export default function ResumePreview({ onShowExportModal }) {
  const { state } = useResume();
  const template = state.meta.template;
  const [exporting, setExporting] = React.useState(false);

  const handleExport = async () => {
    setExporting(true);
    try {
      const name = state.sections.find(s => s.type === 'header')?.data?.name || 'Resume';
      await exportResumePDF(name);
      onShowExportModal();
    } catch (e) {
      console.error(e);
      alert('Export failed. Please check console.');
    } finally {
      setExporting(false);
    }
  };

  const handleShare = () => {
    const hash = btoa(JSON.stringify(state));
    window.location.hash = hash;
    navigator.clipboard.writeText(window.location.href);
    alert('Share link copied to clipboard!');
  };

  let TemplateComponent = ClassicTemplate;
  if (template === 'modern') TemplateComponent = ModernTemplate;
  if (template === 'minimal') TemplateComponent = MinimalTemplate;

  return (
    <div className="relative w-full h-full flex flex-col pt-4 items-center bg-[#F3F4F6]">
      {/* Top Toolbar */}
      <div className="absolute top-4 right-8 z-10 flex space-x-3">
        <button 
          onClick={handleShare}
          className="flex items-center px-4 py-2 bg-white border border-gray-200 text-gray-700 font-medium rounded-lg shadow-sm hover:bg-gray-50 transition-colors"
        >
          <Share2 size={18} className="mr-2" /> Share
        </button>
        <button 
          onClick={handleExport}
          disabled={exporting}
          className="flex items-center px-6 py-2 bg-[#6C63FF] text-white font-medium rounded-lg shadow-md hover:bg-[#5A52E0] transition-colors disabled:opacity-70 group overflow-hidden relative"
        >
          <div className="absolute inset-0 w-full h-full gradient-pulse opacity-0 group-hover:opacity-100 transition-opacity" style={{ background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.2), transparent)', transform: 'skewX(-20deg)', animation: exporting ? 'slide 1.5s infinite' : 'none' }} />
          <Download size={18} className="mr-2" /> 
          {exporting ? 'Exporting...' : 'Export PDF'}
        </button>
      </div>

      {/* Styled animation for button */}
      <style>{`
        @keyframes slide {
          0% { transform: translateX(-100%) skewX(-20deg); }
          100% { transform: translateX(200%) skewX(-20deg); }
        }
      `}</style>

      {/* Scaled Preview Wrapper */}
      <div className="mt-16 sm:mt-12 overflow-visible origin-top lg:scale-[0.8] xl:scale-[0.9] md:scale-[0.6] scale-[0.35] transition-transform flex-1 flex flex-col items-center">
        <div className="bg-white shadow-2xl relative" style={{ width: '794px', minHeight: '1123px' }}>
          <TemplateComponent state={state} />

          {/* Faint A4 boundary line (1123px height) to show page breaks */}
          <div className="absolute left-0 right-0 border-b border-dashed border-red-300 w-full" style={{ top: '1123px', height: '1px' }} title="Page Break (A4)" />
        </div>
      </div>
    </div>
  );
}

import React from 'react';

// A helper to map font pairs to standard CSS font-family strings
export const getFontFamily = (pair) => {
  switch (pair) {
    case 'merriweather-lato':
      return { heading: '"Merriweather", serif', body: '"Lato", sans-serif' };
    case 'playfair-sourcesans':
      return { heading: '"Playfair Display", serif', body: '"Source Sans 3", sans-serif' };
    case 'inter-roboto':
    default:
      return { heading: '"Inter", sans-serif', body: '"Roboto", sans-serif' };
  }
};

export default function ClassicTemplate({ state }) {
  const { meta, sections } = state;
  const fonts = getFontFamily(meta.fontPair);

  const headerSection = sections.find(s => s.type === 'header')?.data || {};

  return (
    <div 
      id="resume-preview" 
      style={{ 
        width: '794px', 
        minHeight: '1123px', 
        backgroundColor: '#FFFFFF', 
        color: '#111827', 
        padding: '12mm 15mm',
        boxSizing: 'border-box',
        fontFamily: fonts.body,
        fontSize: '14px',
        lineHeight: '1.5'
      }}
    >
      {/* Header */}
      <div style={{ textAlign: 'center', marginBottom: '16px' }}>
        <h1 style={{ fontFamily: fonts.heading, fontSize: '28px', fontWeight: 'bold', margin: '0 0 4px 0', color: '#000000' }}>
          {headerSection.name || 'Unnamed'}
        </h1>
        {headerSection.title && <div style={{ fontSize: '16px', fontWeight: '500', marginBottom: '4px' }}>{headerSection.title}</div>}

        <div style={{ display: 'flex', flexWrap: 'wrap', justifyContent: 'center', gap: '8px', fontSize: '12px', color: '#4B5563' }}>
          {headerSection.email && <span>{headerSection.email}</span>}
          {headerSection.phone && <><span style={{color: meta.accentColor}}>•</span><span>{headerSection.phone}</span></>}
          {headerSection.location && <><span style={{color: meta.accentColor}}>•</span><span>{headerSection.location}</span></>}
          {headerSection.linkedin && <><span style={{color: meta.accentColor}}>•</span><span>{headerSection.linkedin}</span></>}
          {headerSection.github && <><span style={{color: meta.accentColor}}>•</span><span>{headerSection.github}</span></>}
          {headerSection.website && <><span style={{color: meta.accentColor}}>•</span><span>{headerSection.website}</span></>}
        </div>
      </div>

      {/* Sections Body */}
      {sections.filter(s => s.type !== 'header' && s.visible).map(sec => {
        return (
          <div key={sec.id} style={{ marginBottom: '16px', pageBreakInside: 'avoid' }}>
            {/* Section Header */}
            <h2 style={{ 
              fontFamily: fonts.heading, 
              fontSize: '14px', 
              fontWeight: 'bold', 
              textTransform: 'uppercase', 
              letterSpacing: '1px', 
              borderBottom: `2px solid ${meta.accentColor}`,
              paddingBottom: '2px',
              marginBottom: '8px',
              color: '#000000'
            }}>
              {sec.type === 'custom' ? (sec.data?.sectionTitle || 'Custom') : sec.type}
            </h2>

            {/* Section Content */}
            <div style={{ fontSize: '13px' }}>
              {sec.type === 'summary' && (
                <p style={{ margin: 0 }}>{sec.data?.text}</p>
              )}

              {sec.type === 'experience' && sec.data?.items?.map(item => (
                <div key={item.id} style={{ marginBottom: '10px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 'bold', color: '#111827' }}>
                    <span>{item.company}</span>
                    <span style={{ fontWeight: 'normal' }}>{item.startDate && `${item.startDate} - ${item.endDate}`}</span>
                  </div>
                  <div style={{ display: 'flex', justifyContent: 'space-between', fontStyle: 'italic', marginBottom: '4px' }}>
                    <span>{item.role}</span>
                    <span style={{ fontSize: '12px' }}>{item.location}</span>
                  </div>
                  {item.bullets && item.bullets.length > 0 && (
                    <ul style={{ margin: 0, paddingLeft: '16px', listStyleType: 'disc' }}>
                      {item.bullets.map((b, i) => <li key={i}>{b}</li>)}
                    </ul>
                  )}
                </div>
              ))}

              {sec.type === 'education' && sec.data?.items?.map(item => (
                <div key={item.id} style={{ marginBottom: '8px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 'bold' }}>
                    <span>{item.institution}</span>
                    <span>{item.startDate && `${item.startDate} - ${item.endDate}`}</span>
                  </div>
                  <div style={{ fontStyle: 'italic' }}>{item.degree}</div>
                  {(item.gpa || item.honors) && (
                    <div style={{ fontSize: '12px', marginTop: '2px' }}>
                      {item.gpa && <span>GPA: {item.gpa} </span>}
                      {item.honors && <span>| {item.honors}</span>}
                    </div>
                  )}
                </div>
              ))}

              {sec.type === 'skills' && (
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '4px 16px' }}>
                  {sec.data?.categories?.map(cat => (
                    <div key={cat.id} style={{ display: 'flex', width: '100%', marginBottom: '2px' }}>
                      <span style={{ fontWeight: 'bold', minWidth: '100px' }}>{cat.label}: </span>
                      <span>{cat.skills?.join(', ')}</span>
                    </div>
                  ))}
                </div>
              )}

              {sec.type === 'projects' && sec.data?.items?.map(item => (
                <div key={item.id} style={{ marginBottom: '10px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 'bold' }}>
                    <span>{item.name} {item.link && <span style={{fontWeight:'normal', fontSize:'12px', color: meta.accentColor}}> - {item.link}</span>}</span>
                    <span style={{ fontStyle: 'italic', fontWeight: 'normal', fontSize: '12px' }}>{item.techStack}</span>
                  </div>
                  {item.description && <div style={{ fontSize: '12px', marginBottom: '4px' }}>{item.description}</div>}
                  {item.bullets && item.bullets.length > 0 && (
                    <ul style={{ margin: 0, paddingLeft: '16px', listStyleType: 'disc' }}>
                      {item.bullets.map((b, i) => <li key={i}>{b}</li>)}
                    </ul>
                  )}
                </div>
              ))}

              {sec.type === 'certifications' && (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                  {sec.data?.items?.map(item => (
                    <div key={item.id} style={{ display: 'flex', justifyContent: 'space-between' }}>
                      <span><strong>{item.name}</strong>, {item.issuer}</span>
                      <span>{item.date}</span>
                    </div>
                  ))}
                </div>
              )}

              {sec.type === 'languages' && (
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '4px' }}>
                  {sec.data?.items?.map(item => (
                    <div key={item.id}>
                      <strong>{item.language}</strong>: {item.proficiency}
                    </div>
                  ))}
                </div>
              )}

              {sec.type === 'custom' && sec.data?.items?.map(item => (
                <div key={item.id} style={{ marginBottom: '8px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 'bold' }}>
                    <span>{item.title}</span>
                    <span style={{ fontWeight: 'normal', fontStyle: 'italic' }}>{item.subtitle}</span>
                  </div>
                  <div style={{ marginTop: '2px' }}>{item.body}</div>
                </div>
              ))}
            </div>
          </div>
        );
      })}
    </div>
  );
}

import React from 'react';
import { useResume } from '../../context/ResumeContext';
import InlineEdit from '../../ui/InlineEdit';
import SortableBullets from '../../ui/SortableBullets';
import { Plus, X } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

export default function ExperienceSection({ section }) {
  const { dispatch } = useResume();
  const items = section.data?.items || [];

  const handleAdd = () => {
    dispatch({
      type: 'ADD_ITEM',
      payload: { sectionId: section.id, item: { id: uuidv4(), company: '', role: '', startDate: '', endDate: '', location: '', bullets: [] } }
    });
  };

  const handleUpdate = (itemId, updates) => {
    dispatch({
      type: 'UPDATE_ITEM',
      payload: { sectionId: section.id, itemId, data: updates }
    });
  };

  const handleRemove = (itemId) => {
    dispatch({ type: 'REMOVE_ITEM', payload: { sectionId: section.id, itemId } });
  };

  return (
    <div className="space-y-6">
      {items.map((item, idx) => (
        <div key={item.id} className="relative group p-4 border border-[#2E2E3D] rounded-lg bg-[#16161D]">
          <button 
            onClick={() => handleRemove(item.id)} 
            className="absolute top-2 right-2 p-1 text-[#8B8A9F] hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
          >
            <X size={16} />
          </button>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-3">
            <div>
              <InlineEdit value={item.role} onChange={(v) => handleUpdate(item.id, { role: v })} placeholder="Job Title" className="text-[#F1F0FF] font-semibold text-base block" />
              <InlineEdit value={item.company} onChange={(v) => handleUpdate(item.id, { company: v })} placeholder="Company Name" className="text-[#6C63FF] text-sm font-medium block mt-1" />
            </div>
            <div className="md:text-right space-y-1">
              <div className="flex md:justify-end items-center space-x-2 text-sm text-[#8B8A9F]">
                <InlineEdit value={item.startDate} onChange={(v) => handleUpdate(item.id, { startDate: v })} placeholder="Start Date" className="w-[80px]" />
                <span>-</span>
                <InlineEdit value={item.endDate} onChange={(v) => handleUpdate(item.id, { endDate: v })} placeholder="End Date" className="w-[80px]" />
              </div>
              <InlineEdit value={item.location} onChange={(v) => handleUpdate(item.id, { location: v })} placeholder="Location" className="text-sm text-[#8B8A9F] block" />
            </div>
          </div>

          <SortableBullets 
            bullets={item.bullets} 
            sectionId={section.id} 
            itemId={item.id} 
            dispatch={dispatch}
            onUpdate={(newBullets) => handleUpdate(item.id, { bullets: newBullets })}
          />
        </div>
      ))}

      <button 
        onClick={handleAdd}
        className="flex items-center justify-center w-full py-3 border-2 border-dashed border-[#2E2E3D] text-[#8B8A9F] hover:border-[#6C63FF] hover:text-[#6C63FF] rounded-lg transition-colors"
      >
        <Plus size={18} className="mr-2" />
        Add Experience
      </button>
    </div>
  );
}

import React, { createContext, useContext, useEffect, useReducer, useCallback, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { seedData } from '../data/seedData';
import { useUndoRedo } from '../hooks/useUndoRedo';
import { decodeState } from '../utils/shareLink';

export const ResumeContext = createContext(null);

const resumeReducer = (state, action) => {
  switch (action.type) {
    case 'SET_TEMPLATE':
      return { ...state, meta: { ...state.meta, template: action.payload } };
    case 'SET_ACCENT_COLOR':
      return { ...state, meta: { ...state.meta, accentColor: action.payload } };
    case 'SET_FONT_PAIR':
      return { ...state, meta: { ...state.meta, fontPair: action.payload } };
    case 'REORDER_SECTIONS':
      return { ...state, sections: action.payload };
    case 'UPDATE_SECTION_DATA':
      return {
        ...state,
        sections: state.sections.map(sec => 
          sec.id === action.payload.sectionId ? { ...sec, data: { ...sec.data, ...action.payload.data } } : sec
        )
      };
    case 'ADD_SECTION':
      return { ...state, sections: [...state.sections, action.payload] };
    case 'REMOVE_SECTION':
      return { ...state, sections: state.sections.filter(sec => sec.id !== action.payload) };
    case 'TOGGLE_SECTION_VISIBILITY':
      return {
        ...state,
        sections: state.sections.map(sec => 
          sec.id === action.payload ? { ...sec, visible: !sec.visible } : sec
        )
      };
    case 'ADD_ITEM': {
      const { sectionId, item } = action.payload;
      return {
        ...state,
        sections: state.sections.map(sec => 
          sec.id === sectionId 
            ? { ...sec, data: { ...sec.data, items: [...(sec.data.items || []), item] } } 
            : sec
        )
      };
    }
    case 'REMOVE_ITEM': {
      const { sectionId, itemId } = action.payload;
      return {
        ...state,
        sections: state.sections.map(sec => 
          sec.id === sectionId 
            ? { ...sec, data: { ...sec.data, items: sec.data.items.filter(i => i.id !== itemId) } } 
            : sec
        )
      };
    }
    case 'UPDATE_ITEM': {
      const { sectionId, itemId, data } = action.payload;
      return {
        ...state,
        sections: state.sections.map(sec => 
          sec.id === sectionId 
            ? { 
                ...sec, 
                data: { 
                  ...sec.data, 
                  items: sec.data.items.map(i => i.id === itemId ? { ...i, ...data } : i) 
                } 
              } 
            : sec
        )
      };
    }
    case 'ADD_BULLET': {
      const { sectionId, itemId, bullet } = action.payload;
      return {
        ...state,
        sections: state.sections.map(sec => 
          sec.id === sectionId 
            ? { 
                ...sec, 
                data: { 
                  ...sec.data, 
                  items: sec.data.items.map(i => 
                    i.id === itemId ? { ...i, bullets: [...(i.bullets || []), bullet] } : i
                  ) 
                } 
              } 
            : sec
        )
      };
    }
    case 'REMOVE_BULLET': {
      const { sectionId, itemId, bulletIndex } = action.payload;
      return {
        ...state,
        sections: state.sections.map(sec => 
          sec.id === sectionId 
            ? { 
                ...sec, 
                data: { 
                  ...sec.data, 
                  items: sec.data.items.map(i => 
                    i.id === itemId ? { ...i, bullets: i.bullets.filter((_, idx) => idx !== bulletIndex) } : i
                  ) 
                } 
              } 
            : sec
        )
      };
    }
    case 'UPDATE_BULLET': {
      const { sectionId, itemId, bulletIndex, bullet } = action.payload;
      return {
        ...state,
        sections: state.sections.map(sec => 
          sec.id === sectionId 
            ? { 
                ...sec, 
                data: { 
                  ...sec.data, 
                  items: sec.data.items.map(i => 
                    i.id === itemId ? { 
                      ...i, 
                      bullets: i.bullets.map((b, idx) => idx === bulletIndex ? bullet : b) 
                    } : i
                  ) 
                } 
              } 
            : sec
        )
      };
    }
    case 'LOAD_STATE':
      return action.payload;
    default:
      return state;
  }
};

export const ResumeContextProvider = ({ children }) => {
  const [savedState, setSavedState] = useState(() => {
    try {
      if (window.location.hash) {
        const decoded = decodeState(window.location.hash);
        if (decoded) {
          window.location.hash = ''; // clear hash so it doesn't persist on reload
          return decoded;
        }
      }
      const local = localStorage.getItem('resumeState');
      return local ? JSON.parse(local) : seedData;
    } catch {
      return seedData;
    }
  });

  const [state, setHistoryState, { undo, redo, canUndo, canRedo }] = useUndoRedo(savedState);

  // Custom dispatch to capture state for undo/redo
  const dispatch = useCallback((action) => {
    if (action.type === 'UNDO') {
      undo();
      return;
    }
    if (action.type === 'REDO') {
      redo();
      return;
    }

    // Calculate new state
    // We get the next state from reducer based on CURRENT state (from history)
    setHistoryState((prevState) => {
      // Actually we need the state from history state index, but setHistoryState needs the new state.
      // useUndoRedo setState takes new explicit state. Let's just use the current top-of-stack state.
      // Wait, we need the latest state from the context.
      return prevState;
    });
  }, [undo, redo, setHistoryState]);

  // Actually, to make useReducer work seamlessly with useUndoRedo, we should manually compute new state:
  const dispatchAction = useCallback((action) => {
    if (action.type === 'UNDO') return undo();
    if (action.type === 'REDO') return redo();
    if (action.type === 'LOAD_STATE') {
      setHistoryState(action.payload);
      return;
    }
    const nextState = resumeReducer(state, action);
    setHistoryState({ ...nextState, meta: { ...nextState.meta, lastSaved: new Date().toISOString() } });
  }, [state, undo, redo, setHistoryState]);

  const saveTimeoutRef = useRef(null);
  useEffect(() => {
    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    saveTimeoutRef.current = setTimeout(() => {
      localStorage.setItem('resumeState', JSON.stringify(state));
    }, 500);
    return () => clearTimeout(saveTimeoutRef.current);
  }, [state]);

  const value = {
    state,
    dispatch: dispatchAction,
    canUndo,
    canRedo
  };

  return (
    <ResumeContext.Provider value={value}>
      {children}
    </ResumeContext.Provider>
  );
};

